import{_ as e,o as a,c as o,a3 as i}from"./chunks/framework.LBeL10WQ.js";const m=JSON.parse('{"title":"Troubleshooting — Distributors","description":"","frontmatter":{"title":"Troubleshooting — Distributors"},"headers":[],"relativePath":"en/faq/troubleshooting-distributors.md","filePath":"en/faq/troubleshooting-distributors.md"}'),s={name:"en/faq/troubleshooting-distributors.md"};function r(n,t,l,d,u,c){return a(),o("div",null,[...t[0]||(t[0]=[i('<h1 id="troubleshooting-—-distributors" tabindex="-1">Troubleshooting — Distributors <a class="header-anchor" href="#troubleshooting-—-distributors" aria-label="Permalink to &quot;Troubleshooting — Distributors&quot;">​</a></h1><p>Your Wallet doesn&#39;t match? A withdrawal is delayed? A campaign is causing a problem? Find the answer in less than 2 minutes.</p><h2 id="wallet-payments" tabindex="-1">Wallet &amp; Payments <a class="header-anchor" href="#wallet-payments" aria-label="Permalink to &quot;Wallet &amp; Payments&quot;">​</a></h2><details class="details custom-block"><summary>&quot;My available balance is 0 even though I distributed campaigns&quot;</summary><p>The Wallet balance is <strong>not automatically</strong> credited after a distribution. You must validate manually according to the format:</p><table tabindex="0"><thead><tr><th>Format</th><th>Required Action</th><th>Where on the platform</th></tr></thead><tbody><tr><td>📦 Parcel Insert</td><td>Declare volumes every <strong>Monday or Tuesday</strong></td><td>My Campaigns → campaign → Declare volume</td></tr><tr><td>📧 Emailing (Dedicated or Display)</td><td>Click on <strong>&quot;Validate broadcast&quot;</strong> after sending</td><td>My Campaigns → campaign → Validate broadcast</td></tr></tbody></table><p>Without these actions, the funds remain <strong>escrowed</strong> — the campaign is not accounted for.</p></details><details class="details custom-block"><summary>&quot;My balance is &#39;pending&#39;, not &#39;available&#39;&quot;</summary><p><strong>Cause:</strong> The 30-day protection period has not yet elapsed.</p><p>Your earnings go through 2 states:</p><ol><li><strong>Pending</strong>: Distribution confirmed, 30-day period underway</li><li><strong>Available</strong>: 30 days elapsed without incident → withdrawal possible</li></ol><blockquote><p><strong>This is normal.</strong> This delay protects everyone (including you) against post-distribution anomalies.</p></blockquote><p>If your funds remain &quot;pending&quot; after 30 days → contact support with the campaign number.</p></details><details class="details custom-block"><summary>&quot;I haven&#39;t received my transfer&quot;</summary><p><strong>Check in this order:</strong></p><ol><li><strong>Have you submitted an invoice?</strong> → Without a valid invoice attached to your request, the payment will not be sent.</li><li><strong>Has the 30-day period passed?</strong> → The balance must be &quot;Available&quot; (not &quot;Pending&quot;).</li><li><strong>Is the IBAN on your account correct?</strong> → Check in Settings → Bank details.</li><li><strong>Are you within the normal timeframe?</strong> → Payment is issued <strong>30 days end of month</strong> after validation of your request.</li></ol><p>If everything is in order and the transfer is still missing → contact <a href="mailto:support@getinside.io" target="_blank" rel="noreferrer">support@getinside.io</a> with:</p><ul><li>The date of the request</li><li>The requested amount</li><li>Your IBAN</li></ul></details><details class="details custom-block"><summary>&quot;A 5% fee was deducted, I don&#39;t understand why&quot;</summary><p>The 5% fee only applies to the <strong>Starter Offer</strong> starting from the <strong>2nd withdrawal of the calendar year</strong>.</p><table tabindex="0"><thead><tr><th>Offer</th><th>Withdrawal fee</th></tr></thead><tbody><tr><td>Starter</td><td>1st withdrawal/year: FREE · Subsequent: 5%</td></tr><tr><td>Platform</td><td>All withdrawals: FREE</td></tr><tr><td>Managed</td><td>All withdrawals: FREE</td></tr></tbody></table><p>If you are on Platform or Managed and a fee was deducted → it&#39;s an error, contact support immediately.</p></details><details class="details custom-block"><summary>&quot;Funds were deducted from my Wallet without my request&quot;</summary><div class="warning custom-block"><p class="custom-block-title">Automatic penalties deducted from your Wallet</p><ul><li><strong>Cancellation of a validated campaign:</strong> flat penalty 250€ + platform fees</li><li><strong>No response within 48h to a proposal:</strong> penalty applied according to contract</li><li><strong>Late response without valid reason:</strong> may result in a penalty</li></ul></div><p>Check the <strong>Wallet History</strong> section on the platform to see the details of each movement.</p></details><details class="details custom-block"><summary>&quot;My funds have expired&quot;</summary><div class="danger custom-block"><p class="custom-block-title">Expiration after 12 months of inactivity</p><p>If you do not log in AND do not withdraw your funds for 12 consecutive months, the available funds are definitively acquired by getinside. This rule is contractual.</p></div><p><strong>Prevention:</strong> Log in at least once a quarter, or schedule an annual withdrawal.</p><p>If you think the expiration is unjustified → contact support with your login history.</p></details><hr><h2 id="campaigns-operations" tabindex="-1">Campaigns &amp; Operations <a class="header-anchor" href="#campaigns-operations" aria-label="Permalink to &quot;Campaigns &amp; Operations&quot;">​</a></h2><details class="details custom-block"><summary>&quot;I accepted a campaign but I can no longer honor it&quot;</summary><p>Act <strong>as early as possible</strong> — penalties increase over time:</p><ol><li><strong>Immediately contact</strong> your account manager or support</li><li><strong>Do not cancel</strong> from the platform without discussing it first</li><li>Explain the situation — an alternative solution is often possible (postponement, replacement by another distributor)</li></ol><blockquote><p>The more you anticipate, the more you limit the penalties. A last-minute cancellation is more costly than an anticipated cancellation.</p></blockquote></details><details class="details custom-block"><summary>&quot;I didn&#39;t answer a campaign proposal within 48h&quot;</summary><p>The 48h rule is contractual. If the deadline is passed:</p><ul><li>The proposal <strong>automatically expires</strong> and is sent to another distributor</li><li>A <strong>penalty may be applied</strong> to your Wallet according to your contract</li><li>Your <strong>Distributor Score</strong> may be impacted (reduced visibility on future campaigns)</li></ul><p><strong>To avoid this in the future:</strong> Enable email/SMS notifications from your Account Settings.</p></details><details class="details custom-block"><summary>&quot;A campaign is incomplete or the received visual/brief is incorrect&quot;</summary><ol><li><strong>Do not</strong> start the distribution without having checked the material</li><li>Report the problem via the platform (campaign profile → Report a problem) or directly contact your manager</li><li>getinside contacts the advertiser to correct — the distribution is paused during the correction</li></ol></details><hr><h2 id="account-affiliation" tabindex="-1">Account &amp; Affiliation <a class="header-anchor" href="#account-affiliation" aria-label="Permalink to &quot;Account &amp; Affiliation&quot;">​</a></h2><details class="details custom-block"><summary>&quot;My referral commissions are not paid&quot;</summary><p>The payment of affiliation commissions is <strong>automatically suspended</strong> if you have unpaid invoices with getinside. Regularize your billing situation to unblock the payments.</p></details><details class="details custom-block"><summary>&quot;My account is suspended or blocked&quot;</summary><p>Possible causes: unpaid invoices, non-compliance with platform rules, suspicious activity detected.</p><p>Contact support at <a href="mailto:support@getinside.io" target="_blank" rel="noreferrer">support@getinside.io</a> indicating your account email and the displayed error message.</p></details><hr><h2 id="can-t-find-your-answer" tabindex="-1">Can&#39;t find your answer? <a class="header-anchor" href="#can-t-find-your-answer" aria-label="Permalink to &quot;Can&#39;t find your answer?&quot;">​</a></h2><ul><li><strong>Email:</strong> <a href="mailto:support@getinside.io" target="_blank" rel="noreferrer">support@getinside.io</a></li><li><strong>Via platform:</strong> Menu → Support → New ticket</li></ul><p>Specify: the campaign ID, the amount in question, and a screenshot if possible.</p><hr><p><strong>See also:</strong> <a href="/handbook/en/publishers/payouts.html">Revenue and Payment Management</a> · <a href="/handbook/en/publishers/onboarding-process.html">Onboarding Process</a></p>',24)])])}const h=e(s,[["render",r]]);export{m as __pageData,h as default};
